Example 10 — Testing Forms

Forms are one of the most important real-world testing scenarios because they involve user input, validation, and submission logic.

// LoginForm.jsx
import { useState } from "react";

function LoginForm({ onSubmit }) {
 const [email, setEmail] = useState("");
 const [error, setError] = useState("");

 function handleSubmit(e) {
 e.preventDefault();

 if (!email) {
 setError("Email is required");
 return;
 }

 setError("");
 onSubmit(email);
 }

 return (
 <form onSubmit={handleSubmit}>
 <label htmlFor="email">
 Email
 </label>

 <input
 id="email"
 type="email"
 value={email}
 onChange={(e) =>
 setEmail(e.target.value)
 }
 />

 {error && (
 <p role="alert">
 {error}
 </p>
 )}

 <button type="submit">
 Submit
 </button>
 </form>
 );
}

export default LoginForm;

 Enter fullscreen mode


 Exit fullscreen mode


Test — Input Change

test("updates input value when user types", async () => {
 render(<LoginForm onSubmit={() => {}} />);

 const input = screen.getByLabelText(
 /email/i
 );

 await userEvent.type(
 input,
 "test@example.com"
 );

 expect(input).toHaveValue(
 "test@example.com"
 );
});

 Enter fullscreen mode


 Exit fullscreen mode


Test — Validation Error

test("shows error when form is submitted without email", async () => {
 render(<LoginForm onSubmit={() => {}} />);

 await userEvent.click(
 screen.getByRole("button", {
 name: /submit/i
 })
 );

 expect(
 screen.getByRole("alert")
 ).toHaveTextContent(
 "Email is required"
 );
});

 Enter fullscreen mode


 Exit fullscreen mode


Test — Successful Submission

import { vi } from "vitest";

test("calls onSubmit with email", async () => {
 const mockSubmit = vi.fn();

 render(
 <LoginForm
 onSubmit={mockSubmit}
 />
 );

 const input = screen.getByLabelText(
 /email/i
 );

 await userEvent.type(
 input,
 "user@test.com"
 );

 await userEvent.click(
 screen.getByRole("button", {
 name: /submit/i
 })
 );

 expect(mockSubmit).toHaveBeenCalledWith(
 "user@test.com"
 );
});

